import React, { useContext, useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { chatAPI } from '../services/api';

// SVGs
const SlotIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 16 16">
    <path d="M14 1a1 1 0 0 1 1 1v12a1 1 0 0 1-1 1H2a1 1 0 0 1-1-1V2a1 1 0 0 1 1-1h12zM2 0a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V2a2 2 0 0 0-2-2H2z"/>
    <path d="M10.97 4.97a.75.75 0 0 1 1.07 1.05l-3.99 4.99a.75.75 0 0 1-1.08.02L4.324 8.384a.75.75 0 1 1 1.06-1.06l2.094 2.093 3.473-4.425a.267.267 0 0 1 .02-.022z"/>
  </svg>
);

const MessageIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 16 16">
    <path d="M2.678 11.894a1 1 0 0 1 .287.801 10.97 10.97 0 0 1-.398 2c1.395-.323 2.247-.697 2.634-.893a1 1 0 0 1 .71-.074A8.06 8.06 0 0 0 8 14c3.996 0 7-2.807 7-6 0-3.192-3.004-6-7-6S1 4.808 1 8c0 1.468.617 2.83 1.678 3.894zm-.493 3.905a21.682 21.682 0 0 1-.713.129c-.2.032-.352-.176-.273-.362a9.68 9.68 0 0 0 .244-.637l.003-.01c.248-.72.45-1.548.524-2.319C.743 11.37 0 9.76 0 8c0-3.866 3.582-7 8-7s8 3.134 8 7-3.582 7-8 7a9.06 9.06 0 0 1-2.347-.306c-.52.263-1.639.742-3.468 1.105z"/>
  </svg>
);

const ResourceIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 16 16">
    <path d="M14 4.5V14a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V2a2 2 0 0 1 2-2h5.5L14 4.5zm-3 0A1.5 1.5 0 0 1 9.5 3V1H4a1 1 0 0 0-1 1v12a1 1 0 0 0 1 1h8a1 1 0 0 0 1-1V4.5h-2z"/>
    <path d="M4.5 12.5A.5.5 0 0 1 5 12h3a.5.5 0 0 1 0 1H5a.5.5 0 0 1-.5-.5zm0-2A.5.5 0 0 1 5 10h6a.5.5 0 0 1 0 1H5a.5.5 0 0 1-.5-.5zm1.639-3.708 1.33.886 1.854-1.855a.25.25 0 0 1 .289-.047l1.888.974V8.5a.5.5 0 0 1-.5.5H5a.5.5 0 0 1-.5-.5V8s1.54-1.274 1.639-1.208zM6.25 6a.75.75 0 1 0 0-1.5.75.75 0 0 0 0 1.5z"/>
  </svg>
);

const ViewBookingsIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="currentColor" viewBox="0 0 16 16">
    <path d="M3.5 0a.5.5 0 0 1 .5.5V1h8V.5a.5.5 0 0 1 1 0V1h1a2 2 0 0 1 2 2v11a2 2 0 0 1-2 2H2a2 2 0 0 1-2-2V3a2 2 0 0 1 2-2h1V.5a.5.5 0 0 1 .5-.5zM1 4v10a1 1 0 0 0 1 1h12a1 1 0 0 0 1-1V4H1z"/>
    <path d="M11 6.5a.5.5 0 0 1 .5-.5h1a.5.5 0 0 1 .5.5v1a.5.5 0 0 1-.5.5h-1a.5.5 0 0 1-.5-.5v-1z"/>
  </svg>
);

const actionCards = [
  {
    title: 'Book Slots',
    description: 'Reserve time with staff members for focused academic support.',
    icon: <SlotIcon />,
    to: '/slots',
  },
  {
    title: 'Messages',
    description: 'Continue discussions with staff or ask quick follow-up questions.',
    icon: <MessageIcon />,
    to: '/chat',
  },
  {
    title: 'Resources',
    description: 'Review uploaded notes, materials, and study references.',
    icon: <ResourceIcon />,
    to: '/materials',
  },
  {
    title: 'My Bookings',
    description: 'Track your scheduled sessions and upcoming learning commitments.',
    icon: <ViewBookingsIcon />,
    to: '/slots?view=booked',
  },
];

const workflowItems = [
  'Review available staff schedules and select a relevant session.',
  'Prepare your questions in advance to make the discussion efficient.',
  'Use chat for follow-up clarification and quick doubt resolution.',
  'Keep materials organized for revision before and after sessions.',
];

const StudentDashboard = () => {
  const { user } = useContext(AuthContext);
  const [unreadTotal, setUnreadTotal] = useState(0);

  useEffect(() => {
    const fetchUnread = async () => {
      try {
        const res = await chatAPI.getUnreadCounts();
        setUnreadTotal(res.data.total || 0);
      } catch (e) {
        console.error('Failed to fetch unread counts', e);
      }
    };
    fetchUnread();
  }, []);

  return (
    <div className="container-fluid py-5 min-vh-100">
      <div className="container">
        <div className="premium-hero-card p-4 p-lg-5 mb-5">
          <span className="premium-hero-kicker">Student Workspace</span>
          <h1 className="premium-hero-title">Welcome back, {user?.name}</h1>
          <p className="premium-hero-copy">
            Plan sessions, stay on top of conversations, and keep your study support organized
            from one premium learning workspace seamlessly blending communication and scheduling.
          </p>
          <div className="premium-hero-grid mt-4">
            <div className="premium-hero-stat">
              <div className="premium-hero-stat-label">Priority</div>
              <div className="premium-hero-stat-value">Upcoming Sessions</div>
            </div>
            <div className="premium-hero-stat">
              <div className="premium-hero-stat-label">Focus</div>
              <div className="premium-hero-stat-value">Clear Doubts Faster</div>
            </div>
            <div className="premium-hero-stat">
              <div className="premium-hero-stat-label">Access</div>
              <div className="premium-hero-stat-value">Resources in One Place</div>
            </div>
          </div>
        </div>

        <div className="row g-4 mb-5">
          {actionCards.map((card) => (
            <div className="col-md-6 col-lg-3" key={card.title}>
              <Link to={card.to} className="text-decoration-none">
                <div className="premium-action-card position-relative">
                  {card.title === 'Messages' && unreadTotal > 0 && (
                    <span className="position-absolute top-0 start-100 translate-middle badge rounded-pill bg-danger" style={{ transform: 'translate(-25%, 25%)', padding: '0.4em 0.8em', fontSize: '0.75rem', zIndex: 10 }}>
                      {unreadTotal} new
                    </span>
                  )}
                  <div className="card-body p-4">
                    <div className="premium-action-icon-wrap">
                      {card.icon}
                    </div>
                    <h5 className="premium-action-title">{card.title}</h5>
                    <p className="premium-action-desc">{card.description}</p>
                  </div>
                </div>
              </Link>
            </div>
          ))}
        </div>

        <div className="row g-4">
          <div className="col-lg-7">
            <div className="premium-panel">
              <div className="premium-panel-header">
                <div className="premium-action-icon-wrap mb-0 bg-success-subtle text-success" style={{ width: '40px', height: '40px' }}>
                   <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="currentColor" viewBox="0 0 16 16">
                    <path d="M8 15A7 7 0 1 1 8 1a7 7 0 0 1 0 14zm0 1A8 8 0 1 0 8 0a8 8 0 0 0 0 16z"/>
                    <path d="m10.97 4.97-.02.022-3.473 4.425-2.093-2.094a.75.75 0 0 0-1.06 1.06L6.427 10.5a.75.75 0 0 0 1.08-.022l3.992-4.99a.75.75 0 0 0-1.06-1.06z"/>
                  </svg>
                </div>
                <h5 className="premium-panel-title">How to Work Effectively</h5>
              </div>
              <div className="premium-panel-body">
                <div className="premium-step-list">
                  {workflowItems.map((item, index) => (
                    <div className="premium-step-item" key={item}>
                      <div className="premium-step-index">{index + 1}</div>
                      <div className="premium-step-content">{item}</div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>

          <div className="col-lg-5">
            <div className="premium-panel">
              <div className="premium-panel-header">
                <div className="premium-action-icon-wrap mb-0" style={{ width: '40px', height: '40px' }}>
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" fill="currentColor" viewBox="0 0 16 16">
                    <path d="M8 16A8 8 0 1 0 8 0a8 8 0 0 0 0 16zm.93-9.412-1 4.705c-.07.34.029.533.304.533.194 0 .487-.07.686-.246l-.088.416c-.287.346-.92.598-1.465.598-.703 0-1.002-.422-.808-1.319l.738-3.468c.064-.293.006-.399-.287-.47l-.451-.081.082-.381 2.29-.287zM8 5.5a1 1 0 1 1 0-2 1 1 0 0 1 0 2z"/>
                  </svg>
                </div>
                <h5 className="premium-panel-title">Study Direction</h5>
              </div>
              <div className="premium-panel-body">
                <div className="premium-meta-list">
                  <div className="premium-meta-item flex-column align-items-start">
                    <span className="premium-meta-label mb-1">Before a session</span>
                    <span className="premium-meta-value text-start w-100" style={{maxWidth: '100%', fontWeight: '500'}}>List the exact concept or problem you want resolved.</span>
                  </div>
                  <div className="premium-meta-item flex-column align-items-start">
                    <span className="premium-meta-label mb-1">During a session</span>
                    <span className="premium-meta-value text-start w-100" style={{maxWidth: '100%', fontWeight: '500'}}>Capture key points and decisions immediately.</span>
                  </div>
                  <div className="premium-meta-item flex-column align-items-start">
                    <span className="premium-meta-label mb-1">After a session</span>
                    <span className="premium-meta-value text-start w-100" style={{maxWidth: '100%', fontWeight: '500'}}>Revisit uploaded materials and confirm unresolved points in chat.</span>
                  </div>
                  <div className="premium-meta-item flex-column align-items-start border-bottom-0 pb-0">
                    <span className="premium-meta-label mb-1">Consistency</span>
                    <span className="premium-meta-value text-start w-100" style={{maxWidth: '100%', fontWeight: '500'}}>Maintain a regular review schedule for stronger retention.</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StudentDashboard;
